//! Runtime mirror of `Gnosis.ScribalStandingWave`.
//!
//! This module is intentionally small and dependency-free so native inference
//! code, gateway adapters, and future Thoth runtimes can share the same
//! boundary/certificate contract without pulling in a proof checker.

pub const SCRIBAL_STANDING_WAVE_THEOREM: &str = "Gnosis.ScribalStandingWave";
pub const THOTH_MECHANICAL_BRAIN_THEOREM: &str =
    "Gnosis.Witnesses.Hermetic.ThothMechanicalBrainFailureWitness";

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ScribalFailureKind {
    Hallucination,
    StaleMemory,
    SourceSubstitution,
    MissingContext,
    Overclaim,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ScribalUseKind {
    AssistedReasoning,
    ScribalMemory,
    MeasuredTranslation,
    FailureAudit,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
pub enum ThothAgenticModality {
    Standard,
    Ask,
    Edit,
    Plan,
    Decide,
    Reason,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
pub enum TaggedTranscriptMode {
    Tagged,
    RawEscape,
}

pub const DEFAULT_THOTH_AGENTIC_MODALITY: ThothAgenticModality = ThothAgenticModality::Standard;
pub const DEFAULT_TAGGED_TRANSCRIPT_MODE: TaggedTranscriptMode = TaggedTranscriptMode::Tagged;
pub const SCRIBAL_TRANSCRIPT_AUDIT_TAG: &str = "thoth.scribal.audit.v1";

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct RustScribalBoundaryInput {
    pub hallucination_observed: bool,
    pub stale_memory_observed: bool,
    pub source_substitution_observed: bool,
    pub missing_context_observed: bool,
    pub overclaim_observed: bool,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct ScribalFailureEvent {
    pub kind: ScribalFailureKind,
    pub observed: bool,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct RustScribalCertificate {
    pub assisted_reasoning_supported: bool,
    pub source_substitution_rejected: bool,
    pub hallucination_rejected: bool,
    pub failure_audit_supported: bool,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct ScribalStandingWaveCertificate {
    pub boundary: RustScribalBoundaryInput,
    pub certificate: RustScribalCertificate,
    pub theorem_lineage: &'static [&'static str],
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct ScribalResponseEnvelope {
    pub events: &'static [ScribalFailureEvent],
    pub boundary_input: RustScribalBoundaryInput,
    pub certificate: RustScribalCertificate,
    pub output_claim: u32,
    pub includes_scribal_theorem: bool,
    pub includes_thoth_theorem: bool,
    pub claims_source_authority: bool,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ScribalAuditTrace {
    pub left: ScribalResponseEnvelope,
    pub right: ScribalResponseEnvelope,
    pub ordered_events: Vec<ScribalFailureEvent>,
    pub compact_boundary_input: RustScribalBoundaryInput,
    pub left_output_claim: u32,
    pub right_output_claim: u32,
    pub trace_use_claim: u32,
    pub includes_scribal_theorem: bool,
    pub includes_thoth_theorem: bool,
    pub claims_source_authority: bool,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct TranscriptTurn {
    pub turn_index: usize,
    pub content: String,
    pub content_hash: u64,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct TaggedTranscriptTurn {
    pub turn: TranscriptTurn,
    pub mode: TaggedTranscriptMode,
    pub envelope: ScribalResponseEnvelope,
    pub audit_tag: Option<&'static str>,
    pub escape_hatch_acknowledged: bool,
    pub claims_source_authority: bool,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
pub struct TranscriptAuditAtom {
    pub turn_index: usize,
    pub content_hash: u64,
    pub mode: TaggedTranscriptMode,
    pub audit_tag_present: bool,
    pub escape_gap: bool,
    pub claims_source_authority: bool,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct TranscriptAuditTrace {
    pub turns: Vec<TaggedTranscriptTurn>,
    pub atoms: Vec<TranscriptAuditAtom>,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct TranscriptRecallPolicy {
    pub current_turn_index: usize,
    pub active_window: usize,
    pub dampened_weight: u32,
    pub amnesia_weight: u32,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct TranscriptRecallAtom {
    pub atom: TranscriptAuditAtom,
    pub active: bool,
    pub dampened: bool,
    pub amnesia_gap: bool,
    pub recall_weight: u32,
    pub claims_source_authority: bool,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct RecallPromotionEvidence {
    pub corroborating_atom: TranscriptAuditAtom,
    pub fresh: bool,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct MemoryBudgetPolicy {
    pub active_budget: usize,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct ScheduledMemoryAtom {
    pub recall: TranscriptRecallAtom,
    pub promoted: bool,
    pub priority: u32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ScheduledTranscriptMemory {
    pub active_memory: Vec<ScheduledMemoryAtom>,
    pub audit_gaps: Vec<TranscriptRecallAtom>,
    pub active_budget: usize,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ThothMemorySession {
    pub modality: ThothAgenticModality,
    pub transcript_trace: TranscriptAuditTrace,
    pub recall_view: Vec<TranscriptRecallAtom>,
    pub scheduled_memory: ScheduledTranscriptMemory,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ThothTranscriptInput {
    pub turn: TranscriptTurn,
    pub raw_escape_requested: bool,
    pub modality: ThothAgenticModality,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ThothMemoryAdapter {
    pub modality: ThothAgenticModality,
    pub session: ThothMemorySession,
    pub generation_context: Vec<ScheduledMemoryAtom>,
    pub audit_gaps: Vec<TranscriptRecallAtom>,
    pub raw_escape_required: bool,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ThothConsumedMemoryContext {
    pub modality: ThothAgenticModality,
    pub active_context: Vec<ScheduledMemoryAtom>,
    pub visible_audit_gaps: Vec<TranscriptRecallAtom>,
    pub source_authority_rejected: bool,
}

pub const DEFAULT_TRANSCRIPT_RECALL_POLICY: TranscriptRecallPolicy = TranscriptRecallPolicy {
    current_turn_index: 0,
    active_window: 8,
    dampened_weight: 25,
    amnesia_weight: 0,
};
pub const DEFAULT_MEMORY_BUDGET_POLICY: MemoryBudgetPolicy =
    MemoryBudgetPolicy { active_budget: 8 };

pub const THEOREM_LINEAGE: &[&str] = &[
    SCRIBAL_STANDING_WAVE_THEOREM,
    THOTH_MECHANICAL_BRAIN_THEOREM,
    "Gnosis.FailureAsStandingWave.support_disjoint_from_falsifications",
];

pub const CANONICAL_BOUNDARY_INPUT: RustScribalBoundaryInput = RustScribalBoundaryInput {
    hallucination_observed: true,
    stale_memory_observed: true,
    source_substitution_observed: true,
    missing_context_observed: true,
    overclaim_observed: true,
};

pub const CANONICAL_FAILURE_EVENT_LOG: &[ScribalFailureEvent] = &[
    ScribalFailureEvent {
        kind: ScribalFailureKind::Hallucination,
        observed: true,
    },
    ScribalFailureEvent {
        kind: ScribalFailureKind::StaleMemory,
        observed: true,
    },
    ScribalFailureEvent {
        kind: ScribalFailureKind::SourceSubstitution,
        observed: true,
    },
    ScribalFailureEvent {
        kind: ScribalFailureKind::MissingContext,
        observed: true,
    },
    ScribalFailureEvent {
        kind: ScribalFailureKind::Overclaim,
        observed: true,
    },
];

pub const CANONICAL_CERTIFICATE: RustScribalCertificate = RustScribalCertificate {
    assisted_reasoning_supported: true,
    source_substitution_rejected: true,
    hallucination_rejected: true,
    failure_audit_supported: true,
};

pub const CANONICAL_SCRIBAL_RESPONSE_ENVELOPE: ScribalResponseEnvelope = ScribalResponseEnvelope {
    events: CANONICAL_FAILURE_EVENT_LOG,
    boundary_input: CANONICAL_BOUNDARY_INPUT,
    certificate: CANONICAL_CERTIFICATE,
    output_claim: 10,
    includes_scribal_theorem: true,
    includes_thoth_theorem: true,
    claims_source_authority: false,
};

pub fn failure_claim(kind: ScribalFailureKind) -> u32 {
    match kind {
        ScribalFailureKind::Hallucination => 0,
        ScribalFailureKind::StaleMemory => 1,
        ScribalFailureKind::SourceSubstitution => 2,
        ScribalFailureKind::MissingContext => 3,
        ScribalFailureKind::Overclaim => 4,
    }
}

pub fn use_claim(kind: ScribalUseKind) -> u32 {
    match kind {
        ScribalUseKind::AssistedReasoning => 10,
        ScribalUseKind::ScribalMemory => 11,
        ScribalUseKind::MeasuredTranslation => 12,
        ScribalUseKind::FailureAudit => 13,
    }
}

pub fn thoth_agentic_modality_claim(modality: ThothAgenticModality) -> u32 {
    match modality {
        ThothAgenticModality::Standard => 20,
        ThothAgenticModality::Ask => 21,
        ThothAgenticModality::Edit => 22,
        ThothAgenticModality::Plan => 23,
        ThothAgenticModality::Decide => 24,
        ThothAgenticModality::Reason => 25,
    }
}

pub fn canonical_failure_boundary(claim: u32) -> bool {
    claim <= failure_claim(ScribalFailureKind::Overclaim)
}

pub fn event_observes(kind: ScribalFailureKind, event: &ScribalFailureEvent) -> bool {
    event.kind == kind && event.observed
}

pub fn event_log_observes(kind: ScribalFailureKind, events: &[ScribalFailureEvent]) -> bool {
    events.iter().any(|event| event_observes(kind, event))
}

pub fn boundary_input_from_event_log(events: &[ScribalFailureEvent]) -> RustScribalBoundaryInput {
    RustScribalBoundaryInput {
        hallucination_observed: event_log_observes(ScribalFailureKind::Hallucination, events),
        stale_memory_observed: event_log_observes(ScribalFailureKind::StaleMemory, events),
        source_substitution_observed: event_log_observes(
            ScribalFailureKind::SourceSubstitution,
            events,
        ),
        missing_context_observed: event_log_observes(ScribalFailureKind::MissingContext, events),
        overclaim_observed: event_log_observes(ScribalFailureKind::Overclaim, events),
    }
}

pub fn event_log_complete(events: &[ScribalFailureEvent]) -> bool {
    let input = boundary_input_from_event_log(events);
    rust_boundary_input_complete(&input)
}

pub fn envelope_boundary_matches(envelope: &ScribalResponseEnvelope) -> bool {
    envelope.boundary_input == boundary_input_from_event_log(envelope.events)
}

pub fn envelope_has_theorem_lineage(envelope: &ScribalResponseEnvelope) -> bool {
    envelope.includes_scribal_theorem && envelope.includes_thoth_theorem
}

pub fn envelope_rejects_source_authority(envelope: &ScribalResponseEnvelope) -> bool {
    !envelope.claims_source_authority
}

pub fn envelope_output_viable(envelope: &ScribalResponseEnvelope) -> bool {
    !canonical_failure_boundary(envelope.output_claim)
}

pub fn scribal_response_envelope_sound(envelope: &ScribalResponseEnvelope) -> bool {
    event_log_complete(envelope.events)
        && envelope_boundary_matches(envelope)
        && rust_certificate_sound(&envelope.certificate)
        && envelope_output_viable(envelope)
        && envelope_has_theorem_lineage(envelope)
        && envelope_rejects_source_authority(envelope)
}

pub fn audit_trace_preserves_ordered_events(trace: &ScribalAuditTrace) -> bool {
    let mut expected = Vec::with_capacity(trace.left.events.len() + trace.right.events.len());
    expected.extend_from_slice(trace.left.events);
    expected.extend_from_slice(trace.right.events);
    trace.ordered_events == expected
}

pub fn audit_trace_boundary_matches_compact_summary(trace: &ScribalAuditTrace) -> bool {
    trace.compact_boundary_input == boundary_input_from_event_log(&trace.ordered_events)
}

pub fn audit_trace_children_sound(trace: &ScribalAuditTrace) -> bool {
    scribal_response_envelope_sound(&trace.left) && scribal_response_envelope_sound(&trace.right)
}

pub fn audit_trace_output_viable(trace: &ScribalAuditTrace) -> bool {
    !canonical_failure_boundary(trace.left_output_claim)
        && !canonical_failure_boundary(trace.right_output_claim)
        && !canonical_failure_boundary(trace.trace_use_claim)
}

pub fn audit_trace_has_theorem_lineage(trace: &ScribalAuditTrace) -> bool {
    trace.includes_scribal_theorem && trace.includes_thoth_theorem
}

pub fn audit_trace_rejects_source_authority(trace: &ScribalAuditTrace) -> bool {
    !trace.claims_source_authority
}

pub fn scribal_audit_trace_sound(trace: &ScribalAuditTrace) -> bool {
    audit_trace_children_sound(trace)
        && audit_trace_preserves_ordered_events(trace)
        && audit_trace_boundary_matches_compact_summary(trace)
        && audit_trace_output_viable(trace)
        && audit_trace_has_theorem_lineage(trace)
        && audit_trace_rejects_source_authority(trace)
}

pub fn fold_scribal_audit_trace(
    left: ScribalResponseEnvelope,
    right: ScribalResponseEnvelope,
) -> ScribalAuditTrace {
    let mut ordered_events = Vec::with_capacity(left.events.len() + right.events.len());
    ordered_events.extend_from_slice(left.events);
    ordered_events.extend_from_slice(right.events);
    let compact_boundary_input = boundary_input_from_event_log(&ordered_events);

    ScribalAuditTrace {
        left,
        right,
        ordered_events,
        compact_boundary_input,
        left_output_claim: left.output_claim,
        right_output_claim: right.output_claim,
        trace_use_claim: use_claim(ScribalUseKind::FailureAudit),
        includes_scribal_theorem: left.includes_scribal_theorem && right.includes_scribal_theorem,
        includes_thoth_theorem: left.includes_thoth_theorem && right.includes_thoth_theorem,
        claims_source_authority: left.claims_source_authority || right.claims_source_authority,
    }
}

pub fn create_thoth_scribal_response_envelope(
    events: &'static [ScribalFailureEvent],
    output_claim: u32,
) -> ScribalResponseEnvelope {
    ScribalResponseEnvelope {
        events,
        boundary_input: boundary_input_from_event_log(events),
        certificate: CANONICAL_CERTIFICATE,
        output_claim,
        includes_scribal_theorem: true,
        includes_thoth_theorem: true,
        claims_source_authority: false,
    }
}

pub fn canonical_scribal_audit_trace() -> ScribalAuditTrace {
    fold_scribal_audit_trace(
        CANONICAL_SCRIBAL_RESPONSE_ENVELOPE,
        CANONICAL_SCRIBAL_RESPONSE_ENVELOPE,
    )
}

pub fn transcript_content_hash(content: &str) -> u64 {
    let mut hash = 0xcbf29ce484222325_u64;
    for byte in content.as_bytes() {
        hash ^= u64::from(*byte);
        hash = hash.wrapping_mul(0x100000001b3);
    }
    hash
}

pub fn create_transcript_turn(turn_index: usize, content: impl Into<String>) -> TranscriptTurn {
    let content = content.into();
    let content_hash = transcript_content_hash(&content);
    TranscriptTurn {
        turn_index,
        content,
        content_hash,
    }
}

pub fn tag_transcript_turn(
    turn: TranscriptTurn,
    mode: TaggedTranscriptMode,
) -> TaggedTranscriptTurn {
    match mode {
        TaggedTranscriptMode::Tagged => TaggedTranscriptTurn {
            turn,
            mode,
            envelope: ScribalResponseEnvelope {
                output_claim: use_claim(ScribalUseKind::FailureAudit),
                ..CANONICAL_SCRIBAL_RESPONSE_ENVELOPE
            },
            audit_tag: Some(SCRIBAL_TRANSCRIPT_AUDIT_TAG),
            escape_hatch_acknowledged: false,
            claims_source_authority: false,
        },
        TaggedTranscriptMode::RawEscape => TaggedTranscriptTurn {
            turn,
            mode,
            envelope: ScribalResponseEnvelope {
                output_claim: use_claim(ScribalUseKind::FailureAudit),
                ..CANONICAL_SCRIBAL_RESPONSE_ENVELOPE
            },
            audit_tag: None,
            escape_hatch_acknowledged: true,
            claims_source_authority: false,
        },
    }
}

pub fn tag_transcript_turn_default(turn: TranscriptTurn) -> TaggedTranscriptTurn {
    tag_transcript_turn(turn, DEFAULT_TAGGED_TRANSCRIPT_MODE)
}

pub fn tagged_transcript_turn_sound(turn: &TaggedTranscriptTurn) -> bool {
    match turn.mode {
        TaggedTranscriptMode::Tagged => {
            turn.audit_tag == Some(SCRIBAL_TRANSCRIPT_AUDIT_TAG)
                && !turn.escape_hatch_acknowledged
                && scribal_response_envelope_sound(&turn.envelope)
                && !turn.claims_source_authority
        }
        TaggedTranscriptMode::RawEscape => {
            turn.audit_tag.is_none()
                && turn.escape_hatch_acknowledged
                && !turn.claims_source_authority
        }
    }
}

pub fn transcript_audit_atom_from_turn(turn: &TaggedTranscriptTurn) -> TranscriptAuditAtom {
    TranscriptAuditAtom {
        turn_index: turn.turn.turn_index,
        content_hash: turn.turn.content_hash,
        mode: turn.mode,
        audit_tag_present: turn.audit_tag == Some(SCRIBAL_TRANSCRIPT_AUDIT_TAG),
        escape_gap: turn.mode == TaggedTranscriptMode::RawEscape,
        claims_source_authority: turn.claims_source_authority,
    }
}

pub fn transcript_audit_atom_sound(atom: &TranscriptAuditAtom) -> bool {
    match atom.mode {
        TaggedTranscriptMode::Tagged => {
            atom.audit_tag_present && !atom.escape_gap && !atom.claims_source_authority
        }
        TaggedTranscriptMode::RawEscape => {
            !atom.audit_tag_present && atom.escape_gap && !atom.claims_source_authority
        }
    }
}

pub fn transcript_audit_join(
    left: &[TranscriptAuditAtom],
    right: &[TranscriptAuditAtom],
) -> Vec<TranscriptAuditAtom> {
    let mut joined = left.to_vec();
    for atom in right {
        if !joined.contains(atom) {
            joined.push(*atom);
        }
    }
    joined
}

pub fn canonical_transcript_audit_atoms(atoms: &[TranscriptAuditAtom]) -> Vec<TranscriptAuditAtom> {
    let mut canonical = transcript_audit_join(&[], atoms);
    canonical.sort();
    canonical
}

pub fn canonical_transcript_audit_join(
    left: &[TranscriptAuditAtom],
    right: &[TranscriptAuditAtom],
) -> Vec<TranscriptAuditAtom> {
    canonical_transcript_audit_atoms(&transcript_audit_join(left, right))
}

pub fn transcript_audit_join_equivalent(
    left: &[TranscriptAuditAtom],
    right: &[TranscriptAuditAtom],
) -> bool {
    canonical_transcript_audit_atoms(left) == canonical_transcript_audit_atoms(right)
}

pub fn transcript_audit_trace_from_turns(turns: &[TaggedTranscriptTurn]) -> TranscriptAuditTrace {
    TranscriptAuditTrace {
        turns: turns.to_vec(),
        atoms: turns.iter().map(transcript_audit_atom_from_turn).collect(),
    }
}

pub fn merge_transcript_audit_trace(
    left: &TranscriptAuditTrace,
    right: &TranscriptAuditTrace,
) -> TranscriptAuditTrace {
    let mut turns = left.turns.clone();
    let left_atoms: Vec<_> = left
        .turns
        .iter()
        .map(transcript_audit_atom_from_turn)
        .collect();
    for turn in &right.turns {
        if !left_atoms.contains(&transcript_audit_atom_from_turn(turn)) {
            turns.push(turn.clone());
        }
    }

    TranscriptAuditTrace {
        turns,
        atoms: transcript_audit_join(&left.atoms, &right.atoms),
    }
}

pub fn transcript_audit_trace_sound(trace: &TranscriptAuditTrace) -> bool {
    trace.atoms.iter().all(transcript_audit_atom_sound)
        && trace
            .turns
            .iter()
            .all(|turn| trace.atoms.contains(&transcript_audit_atom_from_turn(turn)))
        && trace
            .atoms
            .iter()
            .all(|atom| atom.mode != TaggedTranscriptMode::RawEscape || atom.escape_gap)
}

pub fn transcript_atom_age(policy: &TranscriptRecallPolicy, atom: &TranscriptAuditAtom) -> usize {
    policy.current_turn_index.saturating_sub(atom.turn_index)
}

pub fn transcript_recall_atom_from_audit(
    policy: &TranscriptRecallPolicy,
    atom: TranscriptAuditAtom,
) -> TranscriptRecallAtom {
    let active = transcript_atom_age(policy, &atom) <= policy.active_window;
    let amnesia_gap = atom.mode == TaggedTranscriptMode::RawEscape;
    TranscriptRecallAtom {
        atom,
        active,
        dampened: !active && !amnesia_gap,
        amnesia_gap,
        recall_weight: if amnesia_gap {
            policy.amnesia_weight
        } else if active {
            100
        } else {
            policy.dampened_weight
        },
        claims_source_authority: atom.claims_source_authority,
    }
}

pub fn transcript_recall_atom_sound(recall: &TranscriptRecallAtom) -> bool {
    transcript_audit_atom_sound(&recall.atom)
        && !recall.claims_source_authority
        && (!recall.amnesia_gap || recall.recall_weight == 0)
}

pub fn transcript_recall_view(
    policy: &TranscriptRecallPolicy,
    atoms: &[TranscriptAuditAtom],
) -> Vec<TranscriptRecallAtom> {
    canonical_transcript_audit_atoms(atoms)
        .into_iter()
        .map(|atom| transcript_recall_atom_from_audit(policy, atom))
        .collect()
}

pub fn transcript_recall_view_sound(recalls: &[TranscriptRecallAtom]) -> bool {
    recalls.iter().all(transcript_recall_atom_sound)
}

pub fn same_recall_content(left: &TranscriptAuditAtom, right: &TranscriptAuditAtom) -> bool {
    left.content_hash == right.content_hash
}

pub fn recall_promotion_evidence_sound(
    recall: &TranscriptRecallAtom,
    evidence: &RecallPromotionEvidence,
) -> bool {
    recall.dampened
        && !recall.amnesia_gap
        && evidence.fresh
        && evidence.corroborating_atom.mode == TaggedTranscriptMode::Tagged
        && evidence.corroborating_atom.audit_tag_present
        && !evidence.corroborating_atom.claims_source_authority
        && same_recall_content(&recall.atom, &evidence.corroborating_atom)
}

pub fn promote_recall_atom(
    recall: TranscriptRecallAtom,
    evidence: &RecallPromotionEvidence,
) -> TranscriptRecallAtom {
    if recall_promotion_evidence_sound(&recall, evidence) {
        TranscriptRecallAtom {
            active: true,
            dampened: false,
            recall_weight: 100,
            ..recall
        }
    } else {
        recall
    }
}

pub fn promoted_recall_atom_sound(
    recall: TranscriptRecallAtom,
    evidence: &RecallPromotionEvidence,
) -> bool {
    transcript_recall_atom_sound(&promote_recall_atom(recall, evidence))
}

pub fn recall_has_promotion_evidence(
    recall: &TranscriptRecallAtom,
    evidence: &[RecallPromotionEvidence],
) -> bool {
    evidence
        .iter()
        .any(|candidate| recall_promotion_evidence_sound(recall, candidate))
}

pub fn scheduled_memory_atom_from_recall(
    evidence: &[RecallPromotionEvidence],
    recall: TranscriptRecallAtom,
) -> ScheduledMemoryAtom {
    let promotion_evidence = evidence
        .iter()
        .find(|candidate| recall_promotion_evidence_sound(&recall, candidate));
    let promoted = promotion_evidence.is_some();
    let promoted_recall = promotion_evidence
        .map(|candidate| promote_recall_atom(recall, candidate))
        .unwrap_or(recall);

    ScheduledMemoryAtom {
        recall: promoted_recall,
        promoted,
        priority: if promoted {
            3
        } else if recall.active {
            2
        } else if recall.dampened {
            1
        } else {
            0
        },
    }
}

pub fn schedule_transcript_memory(
    policy: &MemoryBudgetPolicy,
    recalls: &[TranscriptRecallAtom],
    evidence: &[RecallPromotionEvidence],
) -> ScheduledTranscriptMemory {
    let mut active_memory: Vec<_> = recalls
        .iter()
        .copied()
        .filter(|recall| !recall.amnesia_gap)
        .map(|recall| scheduled_memory_atom_from_recall(evidence, recall))
        .collect();
    active_memory.sort_by(|left, right| right.priority.cmp(&left.priority));
    active_memory.truncate(policy.active_budget);

    ScheduledTranscriptMemory {
        active_memory,
        audit_gaps: recalls
            .iter()
            .copied()
            .filter(|recall| recall.amnesia_gap)
            .collect(),
        active_budget: policy.active_budget,
    }
}

pub fn scheduled_transcript_memory_sound(schedule: &ScheduledTranscriptMemory) -> bool {
    schedule.active_memory.len() <= schedule.active_budget
        && schedule.active_memory.iter().all(|atom| {
            transcript_recall_atom_sound(&atom.recall)
                && !atom.recall.amnesia_gap
                && !atom.recall.claims_source_authority
        })
        && schedule
            .audit_gaps
            .iter()
            .all(|gap| gap.amnesia_gap && !gap.claims_source_authority)
}

pub fn build_thoth_memory_session(
    recall_policy: &TranscriptRecallPolicy,
    budget_policy: &MemoryBudgetPolicy,
    turns: &[TaggedTranscriptTurn],
    evidence: &[RecallPromotionEvidence],
) -> ThothMemorySession {
    build_thoth_memory_session_with_modality(
        DEFAULT_THOTH_AGENTIC_MODALITY,
        recall_policy,
        budget_policy,
        turns,
        evidence,
    )
}

pub fn build_thoth_memory_session_with_modality(
    modality: ThothAgenticModality,
    recall_policy: &TranscriptRecallPolicy,
    budget_policy: &MemoryBudgetPolicy,
    turns: &[TaggedTranscriptTurn],
    evidence: &[RecallPromotionEvidence],
) -> ThothMemorySession {
    let transcript_trace = transcript_audit_trace_from_turns(turns);
    let recall_view = transcript_recall_view(recall_policy, &transcript_trace.atoms);
    let scheduled_memory = schedule_transcript_memory(budget_policy, &recall_view, evidence);
    ThothMemorySession {
        modality,
        transcript_trace,
        recall_view,
        scheduled_memory,
    }
}

pub fn merge_thoth_memory_session(
    recall_policy: &TranscriptRecallPolicy,
    budget_policy: &MemoryBudgetPolicy,
    left: &ThothMemorySession,
    right: &ThothMemorySession,
    evidence: &[RecallPromotionEvidence],
) -> ThothMemorySession {
    let modality = if left.modality == right.modality {
        left.modality
    } else {
        DEFAULT_THOTH_AGENTIC_MODALITY
    };
    let transcript_trace =
        merge_transcript_audit_trace(&left.transcript_trace, &right.transcript_trace);
    let recall_view = transcript_recall_view(recall_policy, &transcript_trace.atoms);
    let scheduled_memory = schedule_transcript_memory(budget_policy, &recall_view, evidence);
    ThothMemorySession {
        modality,
        transcript_trace,
        recall_view,
        scheduled_memory,
    }
}

pub fn thoth_memory_session_sound(session: &ThothMemorySession) -> bool {
    transcript_audit_trace_sound(&session.transcript_trace)
        && transcript_recall_view_sound(&session.recall_view)
        && scheduled_transcript_memory_sound(&session.scheduled_memory)
}

pub fn thoth_memory_session_rejects_source_authority(session: &ThothMemorySession) -> bool {
    session
        .scheduled_memory
        .active_memory
        .iter()
        .all(|atom| !atom.recall.claims_source_authority)
        && session
            .scheduled_memory
            .audit_gaps
            .iter()
            .all(|gap| !gap.claims_source_authority)
}

pub fn create_thoth_transcript_input(
    turn_index: usize,
    content: impl Into<String>,
    raw_escape_requested: bool,
) -> ThothTranscriptInput {
    create_thoth_transcript_input_with_modality(
        turn_index,
        content,
        raw_escape_requested,
        DEFAULT_THOTH_AGENTIC_MODALITY,
    )
}

pub fn create_thoth_transcript_input_with_modality(
    turn_index: usize,
    content: impl Into<String>,
    raw_escape_requested: bool,
    modality: ThothAgenticModality,
) -> ThothTranscriptInput {
    ThothTranscriptInput {
        turn: create_transcript_turn(turn_index, content),
        raw_escape_requested,
        modality,
    }
}

pub fn thoth_transcript_input_to_tagged_turn(input: &ThothTranscriptInput) -> TaggedTranscriptTurn {
    tag_transcript_turn(
        input.turn.clone(),
        if input.raw_escape_requested {
            TaggedTranscriptMode::RawEscape
        } else {
            DEFAULT_TAGGED_TRANSCRIPT_MODE
        },
    )
}

pub fn build_thoth_memory_adapter(
    recall_policy: &TranscriptRecallPolicy,
    budget_policy: &MemoryBudgetPolicy,
    inputs: &[ThothTranscriptInput],
    evidence: &[RecallPromotionEvidence],
) -> ThothMemoryAdapter {
    let modality = inputs
        .first()
        .map(|input| input.modality)
        .unwrap_or(DEFAULT_THOTH_AGENTIC_MODALITY);
    build_thoth_memory_adapter_with_modality(
        modality,
        recall_policy,
        budget_policy,
        inputs,
        evidence,
    )
}

pub fn build_thoth_memory_adapter_with_modality(
    modality: ThothAgenticModality,
    recall_policy: &TranscriptRecallPolicy,
    budget_policy: &MemoryBudgetPolicy,
    inputs: &[ThothTranscriptInput],
    evidence: &[RecallPromotionEvidence],
) -> ThothMemoryAdapter {
    let turns: Vec<_> = inputs
        .iter()
        .map(thoth_transcript_input_to_tagged_turn)
        .collect();
    let session = build_thoth_memory_session_with_modality(
        modality,
        recall_policy,
        budget_policy,
        &turns,
        evidence,
    );
    ThothMemoryAdapter {
        modality,
        generation_context: session.scheduled_memory.active_memory.clone(),
        audit_gaps: session.scheduled_memory.audit_gaps.clone(),
        raw_escape_required: inputs.iter().any(|input| input.raw_escape_requested),
        session,
    }
}

pub fn thoth_memory_adapter_sound(adapter: &ThothMemoryAdapter) -> bool {
    thoth_memory_session_sound(&adapter.session)
        && thoth_memory_session_rejects_source_authority(&adapter.session)
        && adapter.generation_context.iter().all(|atom| {
            transcript_recall_atom_sound(&atom.recall)
                && !atom.recall.amnesia_gap
                && !atom.recall.claims_source_authority
        })
        && adapter
            .audit_gaps
            .iter()
            .all(|gap| gap.amnesia_gap && !gap.claims_source_authority)
}

pub fn consume_thoth_memory_adapter(adapter: &ThothMemoryAdapter) -> ThothConsumedMemoryContext {
    ThothConsumedMemoryContext {
        modality: adapter.modality,
        active_context: adapter.generation_context.clone(),
        visible_audit_gaps: adapter.audit_gaps.clone(),
        source_authority_rejected: adapter
            .generation_context
            .iter()
            .all(|atom| !atom.recall.claims_source_authority)
            && adapter
                .audit_gaps
                .iter()
                .all(|gap| !gap.claims_source_authority),
    }
}

pub fn thoth_consumed_memory_context_sound(context: &ThothConsumedMemoryContext) -> bool {
    context.source_authority_rejected
        && context.active_context.iter().all(|atom| {
            transcript_recall_atom_sound(&atom.recall)
                && !atom.recall.amnesia_gap
                && !atom.recall.claims_source_authority
        })
        && context
            .visible_audit_gaps
            .iter()
            .all(|gap| gap.amnesia_gap && !gap.claims_source_authority)
}

pub fn rust_boundary_input_complete(input: &RustScribalBoundaryInput) -> bool {
    input.hallucination_observed
        && input.stale_memory_observed
        && input.source_substitution_observed
        && input.missing_context_observed
        && input.overclaim_observed
}

pub fn rust_certificate_sound(certificate: &RustScribalCertificate) -> bool {
    certificate.assisted_reasoning_supported
        && certificate.source_substitution_rejected
        && certificate.hallucination_rejected
        && certificate.failure_audit_supported
}

pub fn canonical_scribal_standing_wave_certificate() -> ScribalStandingWaveCertificate {
    ScribalStandingWaveCertificate {
        boundary: CANONICAL_BOUNDARY_INPUT,
        certificate: CANONICAL_CERTIFICATE,
        theorem_lineage: THEOREM_LINEAGE,
    }
}

pub fn validate_scribal_standing_wave_certificate(
    certificate: &ScribalStandingWaveCertificate,
) -> bool {
    rust_boundary_input_complete(&certificate.boundary)
        && rust_certificate_sound(&certificate.certificate)
        && certificate
            .theorem_lineage
            .contains(&SCRIBAL_STANDING_WAVE_THEOREM)
        && certificate
            .theorem_lineage
            .contains(&THOTH_MECHANICAL_BRAIN_THEOREM)
}

