    #[test]
    fn canonical_transcript_audit_join_satisfies_crdt_laws() {
        let first = transcript_audit_atom_from_turn(&tag_transcript_turn_default(
            create_transcript_turn(0, "a"),
        ));
        let second = transcript_audit_atom_from_turn(&tag_transcript_turn_default(
            create_transcript_turn(1, "b"),
        ));
        let gap = transcript_audit_atom_from_turn(&tag_transcript_turn(
            create_transcript_turn(2, "gap"),
            TaggedTranscriptMode::RawEscape,
        ));

        assert_eq!(
            canonical_transcript_audit_join(&[first], &[first]),
            vec![first]
        );
        assert!(transcript_audit_join_equivalent(
            &canonical_transcript_audit_join(&[first], &[second]),
            &canonical_transcript_audit_join(&[second], &[first])
        ));
        assert!(transcript_audit_join_equivalent(
            &canonical_transcript_audit_join(
                &canonical_transcript_audit_join(&[first], &[second]),
                &[gap]
            ),
            &canonical_transcript_audit_join(
                &[first],
                &canonical_transcript_audit_join(&[second], &[gap])
            )
        ));
    }

    #[test]
    fn transcript_recall_view_dampens_old_atoms_and_marks_amnesia_gaps() {
        let old = transcript_audit_atom_from_turn(&tag_transcript_turn_default(
            create_transcript_turn(0, "old"),
        ));
        let recent = transcript_audit_atom_from_turn(&tag_transcript_turn_default(
            create_transcript_turn(9, "recent"),
        ));
        let gap = transcript_audit_atom_from_turn(&tag_transcript_turn(
            create_transcript_turn(10, "raw"),
            TaggedTranscriptMode::RawEscape,
        ));
        let policy = TranscriptRecallPolicy {
            current_turn_index: 10,
            active_window: 2,
            ..DEFAULT_TRANSCRIPT_RECALL_POLICY
        };
        let recalls = transcript_recall_view(&policy, &[old, recent, gap]);

        assert!(transcript_recall_view_sound(&recalls));
        let old_recall = recalls.iter().find(|recall| recall.atom == old).unwrap();
        assert!(old_recall.dampened);
        assert_eq!(old_recall.recall_weight, policy.dampened_weight);

        let recent_recall = recalls.iter().find(|recall| recall.atom == recent).unwrap();
        assert!(recent_recall.active);
        assert_eq!(recent_recall.recall_weight, 100);

        let gap_recall = recalls.iter().find(|recall| recall.atom == gap).unwrap();
        assert!(gap_recall.amnesia_gap);
        assert_eq!(gap_recall.recall_weight, 0);
    }

    #[test]
    fn recall_promotion_requires_fresh_tagged_corroboration() {
        let old = transcript_audit_atom_from_turn(&tag_transcript_turn_default(
            create_transcript_turn(0, "memory"),
        ));
        let policy = TranscriptRecallPolicy {
            current_turn_index: 10,
            active_window: 2,
            ..DEFAULT_TRANSCRIPT_RECALL_POLICY
        };
        let recall = transcript_recall_view(&policy, &[old])[0];
        let corroborating_atom = TranscriptAuditAtom {
            turn_index: 11,
            ..old
        };
        let evidence = RecallPromotionEvidence {
            corroborating_atom,
            fresh: true,
        };

        assert!(recall.dampened);
        assert!(recall_promotion_evidence_sound(&recall, &evidence));
        let promoted = promote_recall_atom(recall, &evidence);
        assert!(promoted.active);
        assert!(!promoted.dampened);
        assert_eq!(promoted.recall_weight, 100);
        assert!(promoted_recall_atom_sound(recall, &evidence));
    }

    #[test]
    fn recall_promotion_rejects_stale_evidence_and_raw_gaps() {
        let old = transcript_audit_atom_from_turn(&tag_transcript_turn_default(
            create_transcript_turn(0, "memory"),
        ));
        let raw_gap = transcript_audit_atom_from_turn(&tag_transcript_turn(
            create_transcript_turn(11, "memory"),
            TaggedTranscriptMode::RawEscape,
        ));
        let policy = TranscriptRecallPolicy {
            current_turn_index: 10,
            active_window: 2,
            ..DEFAULT_TRANSCRIPT_RECALL_POLICY
        };
        let recall = transcript_recall_view(&policy, &[old])[0];

        assert_eq!(
            promote_recall_atom(
                recall,
                &RecallPromotionEvidence {
                    corroborating_atom: old,
                    fresh: false,
                },
            ),
            recall
        );
        assert_eq!(
            promote_recall_atom(
                recall,
                &RecallPromotionEvidence {
                    corroborating_atom: raw_gap,
                    fresh: true,
                },
            ),
            recall
        );
    }

    #[test]
    fn schedules_active_memory_under_budget_with_promoted_atoms_first() {
        let old = transcript_audit_atom_from_turn(&tag_transcript_turn_default(
            create_transcript_turn(0, "memory"),
        ));
        let recent = transcript_audit_atom_from_turn(&tag_transcript_turn_default(
            create_transcript_turn(9, "recent"),
        ));
        let gap = transcript_audit_atom_from_turn(&tag_transcript_turn(
            create_transcript_turn(10, "raw"),
            TaggedTranscriptMode::RawEscape,
        ));
        let recalls = transcript_recall_view(
            &TranscriptRecallPolicy {
                current_turn_index: 10,
                active_window: 2,
                ..DEFAULT_TRANSCRIPT_RECALL_POLICY
            },
            &[old, recent, gap],
        );
        let schedule = schedule_transcript_memory(
            &MemoryBudgetPolicy { active_budget: 2 },
            &recalls,
            &[RecallPromotionEvidence {
                corroborating_atom: TranscriptAuditAtom {
                    turn_index: 11,
                    ..old
                },
                fresh: true,
            }],
        );

        assert!(scheduled_transcript_memory_sound(&schedule));
        assert_eq!(schedule.active_memory.len(), 2);
        assert!(schedule.active_memory[0].promoted);
        assert_eq!(schedule.active_memory[0].recall.recall_weight, 100);
        assert!(schedule
            .active_memory
            .iter()
            .all(|atom| !atom.recall.amnesia_gap));
        assert_eq!(schedule.audit_gaps.len(), 1);
        assert!(schedule.audit_gaps[0].amnesia_gap);
    }

    #[test]
    fn scheduler_keeps_dampened_atoms_when_budget_permits_and_rejects_authority() {
        let old = transcript_audit_atom_from_turn(&tag_transcript_turn_default(
            create_transcript_turn(0, "old"),
        ));
        let recalls = transcript_recall_view(
            &TranscriptRecallPolicy {
                current_turn_index: 10,
                active_window: 2,
                ..DEFAULT_TRANSCRIPT_RECALL_POLICY
            },
            &[old],
        );
        let schedule =
            schedule_transcript_memory(&MemoryBudgetPolicy { active_budget: 3 }, &recalls, &[]);

        assert!(scheduled_transcript_memory_sound(&schedule));
        assert_eq!(schedule.active_memory.len(), 1);
        assert!(schedule.active_memory[0].recall.dampened);

        let mut authority_schedule = schedule.clone();
        authority_schedule.active_memory[0]
            .recall
            .claims_source_authority = true;
        assert!(!scheduled_transcript_memory_sound(&authority_schedule));
    }

    #[test]
    fn builds_sound_thoth_memory_session_from_tagged_turns_to_schedule() {
        let tagged = tag_transcript_turn_default(create_transcript_turn(0, "memory"));
        let raw = tag_transcript_turn(
            create_transcript_turn(10, "raw"),
            TaggedTranscriptMode::RawEscape,
        );
        let old_atom = transcript_audit_atom_from_turn(&tagged);
        let session = build_thoth_memory_session(
            &TranscriptRecallPolicy {
                current_turn_index: 10,
                active_window: 2,
                ..DEFAULT_TRANSCRIPT_RECALL_POLICY
            },
            &MemoryBudgetPolicy { active_budget: 2 },
            &[tagged, raw],
            &[RecallPromotionEvidence {
                corroborating_atom: TranscriptAuditAtom {
                    turn_index: 11,
                    ..old_atom
                },
                fresh: true,
            }],
        );

        assert!(thoth_memory_session_sound(&session));
        assert!(thoth_memory_session_rejects_source_authority(&session));
        assert_eq!(session.modality, DEFAULT_THOTH_AGENTIC_MODALITY);
        assert!(session.scheduled_memory.active_memory[0].promoted);
        assert_eq!(session.scheduled_memory.audit_gaps.len(), 1);
    }

