    #[test]
    fn merges_thoth_memory_sessions_without_promoting_raw_escapes() {
        let left_turn = tag_transcript_turn_default(create_transcript_turn(0, "left"));
        let right_turn = tag_transcript_turn_default(create_transcript_turn(1, "right"));
        let raw = tag_transcript_turn(
            create_transcript_turn(2, "raw"),
            TaggedTranscriptMode::RawEscape,
        );
        let recall_policy = TranscriptRecallPolicy {
            current_turn_index: 2,
            active_window: 2,
            ..DEFAULT_TRANSCRIPT_RECALL_POLICY
        };
        let budget_policy = MemoryBudgetPolicy { active_budget: 3 };
        let left = build_thoth_memory_session(&recall_policy, &budget_policy, &[left_turn], &[]);
        let right =
            build_thoth_memory_session(&recall_policy, &budget_policy, &[right_turn, raw], &[]);
        let merged = merge_thoth_memory_session(&recall_policy, &budget_policy, &left, &right, &[]);

        assert!(thoth_memory_session_sound(&merged));
        assert!(thoth_memory_session_rejects_source_authority(&merged));
        assert_eq!(merged.transcript_trace.atoms.len(), 3);
        assert_eq!(merged.scheduled_memory.audit_gaps.len(), 1);
        assert!(merged
            .scheduled_memory
            .active_memory
            .iter()
            .all(|atom| !atom.recall.amnesia_gap));
    }

